import React, { useState } from 'react';
import { useLocation } from 'react-router-dom';
import classNames from 'classnames';
// import { useRouteMatch, } from 'react-router-dom';
import PropTypes from 'prop-types';

import './HomePage.scss';

// eslint-disable-next-line react/prop-types
export const HomePage = ({ newsTrending, newsCategory, setArticle }) => {
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const category = searchParams.get('category');
  const [preview, setPreview] = useState();
  const value = {
    title: 'Covid survivors still at reinfection risk from Alpha, Beta variants',
    description: 'Immune response following a coronavirus infection can vary between individuals and may not be enough to fight Alpha, and Beta variant of Covid-19, finds a study reinforcing the need for vaccination.',
    content: 'Follow us on Image Source : AP Covid survivors still at reinfection risk from Alpha, Beta variants (Representational Image)\nImmune response following a coronavirus infection can vary between individuals and may not be enough to fight Alpha, and Beta ... [2547 chars]',
    url: 'https://www.indiatvnews.com/news/world/covid-survivors-still-at-reinfection-risk-from-alpha-beta-variants-713343',
    image: 'https://resize.indiatvnews.com/en/resize/newbucket/715_-/2021/06/us-virus-variant-1624207087.jpeg',
    publishedAt: '2021-06-20T16:38:37Z',
    source: {
      name: 'India TV News',
      url: 'https://www.indiatvnews.com',
    },
  };

  // let dat = new Date(value.publishedAt
  //   .slice(0, 10))
  //   .toString()
  //   .slice(4, 15);
  console.log(preview);
  console.log(category);
  console.log(newsCategory);
  // console.log(dat);

  return (
    <div className="HomePage">
      {preview && (
        <div className={classNames('HomePage-Preview Preview', {
          is_visible: {},
        })}
        >
          <div className="Preview-Content">
            <button
              type="button"
              className="Preview-Title"
              onClick={() => {}}
            >
              {/* {preview.title} */}
              Covid survivors still at reinfection risk from Alpha, Beta variants
            </button>
            <p className="Preview-Description">
              {/* It is a long established fact that a reader will be distracted by the readable content of a page when looking at its layout. The point of using Lorem Ipsum is that.... */}
              {/* {preview.description} */}
              {value.description}
              {/* Follow us on Image Source : AP Covid survivors still at reinfection risk from Alpha, Beta variants (Representational Image)\nImmune response following a coronavirus infection can vary between individuals and may not be enough to fight Alpha, and Beta ... [2547 chars] */}
            </p>
            <div className="Preview-Read">
              <p className="Preview-Date">{new Date(value.publishedAt.slice(0, 10)).toString().slice(4, 15)}</p>
              <button
                type="button"
                className="Preview-Button"
                onClick={() => {
                  setArticle(value)}}
              >
                Read more
              </button>
            </div>
          </div>
          <div className="Preview-Image">
            <img
              className="image-preview"
              src="https://resize.indiatvnews.com/en/resize/newbucket/715_-/2021/06/us-virus-variant-1624207087.jpeg"
              //src={preview.image}
              // width="700"
              //height="100%"
              alt="Foto"
            />
          </div>
        </div>
      )}

      <div className="HomePage-Container">
        {/* {(category ? newsCategory : newsTrending) */}
        {['1', '2', '3', '4', '5', '6'].map((item, index) => (
          <div
            className="HomePage-ContentNews News"
            //key={`${item.title + index}`}
            key={item}
          >
            <div className="News-Image">
              <img
                className="image-news"
                src="https://resize.indiatvnews.com/en/resize/newbucket/715_-/2021/06/us-virus-variant-1624207087.jpeg"
                // src="https://www.bing.com/th?id=OVFT.MRlwUuzOuHZVkEAPjnYivi&pid=News"
                //src={item.image}
                //width="350"
                // height="200"
                height="179"
                alt="Foto"
              />
            </div>
            <div className="News-Content">
              <button
                type="button"
                className="News-Title"
                onClick={() => {}}
              >
                {/* long established */}
                {/* {item.title} */}
                Covid survivors still at reinfection risk from Alpha, Beta variants
              </button>
              <p className="News-Description">
                {/* {item.description} */}
                {(value.description).length > 167 ? value.description.slice(0, 163) + '...' : value.description}
                {/* It is a long established fact that a reader will be distracted by the readable content of a page when looking at its layout. The point of using Lorem Ipsum is that.... */}
              </p>
              <div className="News-Read">
                <p className="News-Date">{new Date(value.publishedAt.slice(0, 10)).toString().slice(4, 15)}</p>
                <button
                  type="button"
                  className="News-Button"
                  onClick={() => setPreview(item)}
                >
                  Read more
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

HomePage.propTypes = {
  newsTrending: PropTypes.arrayOf({
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
  }.isRequired).isRequired,
  setArticle: PropTypes.func.isRequired,
};

HomePage.defaultProps = {
  // eslint-disable-next-line react/default-props-match-prop-types
  newsCategory: [],
};
